Code.Terraform:
```hcl
# Terraform：确保 WAF Classic 全局规则组至少有一条规则
resource "aws_waf_rule_group" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "examplemetric"

  activated_rule {
    priority = 1                      # 关键：向该组添加一条规则（使其不再为空）
    rule_id  = "<example_resource_id>" # 关键：要添加的现有规则的 ID
    action {
      type = "BLOCK"                 # 关键：激活该规则时需要执行的操作
    }
  }
}
```
